"use client";

import * as React from "react";
import type { Tooltip as TooltipPrimitive } from "radix-ui";

import type { AlignType } from "../../types";
import {
  TooltipContent,
  TooltipProvider,
  TooltipRoot,
  TooltipTrigger,
} from "./_components";

export type TooltipPlacement =
  | "top"
  | "left"
  | "right"
  | "bottom"
  | "topLeft"
  | "topRight"
  | "bottomLeft"
  | "bottomRight"
  | "leftTop"
  | "leftBottom"
  | "rightTop"
  | "rightBottom";
export type AbstractTooltipProps = {
  placement?: TooltipPlacement;
};

type TooltipProps = AbstractTooltipProps &
  Omit<React.ComponentProps<typeof TooltipPrimitive.Root>, "side"> & {
    /**
     * The text shown in the tooltip
     */
    title?: React.ReactNode;
    placement?: TooltipPlacement;
    hidden?: boolean;
    classNames?: {
      title?: string;
      arrow?: string;
    };
    styles?: {
      title?: React.CSSProperties;
      arrow?: React.CSSProperties;
    };
    align?: AlignType;
  };
const Tooltip = (props: TooltipProps) => {
  const triggerRef = React.useRef(null);

  const isShadcnTooltip = !("title" in props);
  if (isShadcnTooltip) return <TooltipRoot {...props} />;

  if (!props.title) {
    return <>{props.children}</>;
  }

  const {
    children,
    title,
    placement,
    hidden,
    classNames,
    styles,
    align: domAlign,
    ...restProps
  } = props;

  let side: "top" | "right" | "bottom" | "left" = "bottom";
  if (placement?.includes("top")) {
    side = "top";
  } else if (placement?.includes("right")) {
    side = "right";
  } else if (placement?.includes("left")) {
    side = "left";
  }

  let align: "start" | "center" | "end" = "center";
  if (placement?.includes("Top")) {
    align = "start";
  } else if (placement?.includes("Left")) {
    align = "start";
  } else if (placement?.includes("Right")) {
    align = "end";
  }

  const alignOffset = domAlign?.offset?.[0];
  const sideOffset = domAlign?.offset?.[1];

  return (
    <>
      <TooltipProvider delayDuration={100}>
        <TooltipRoot {...restProps}>
          <TooltipTrigger
            ref={triggerRef}
            asChild
            // keep tooltip open when trigger is clicked
            onClick={(event) => event.preventDefault()}
          >
            {children}
          </TooltipTrigger>
          <TooltipContent
            side={side}
            align={align}
            alignOffset={alignOffset}
            sideOffset={sideOffset}
            hidden={hidden}
            // keep tooltip open when trigger is clicked
            onPointerDownOutside={(event) => {
              if (event.target === triggerRef.current) event.preventDefault();
            }}
            className={classNames?.title}
            style={styles?.title}
            classNames={
              classNames?.arrow ? { arrow: classNames.arrow } : undefined
            }
            styles={styles?.arrow ? { arrow: styles.arrow } : undefined}
          >
            {title}
          </TooltipContent>
        </TooltipRoot>
      </TooltipProvider>
    </>
  );
};

export { Tooltip };
export type { TooltipProps };

import { Tooltip as TooltipPrimitive } from "radix-ui";

import { cn } from "../../lib/utils";

function TooltipContent({
  className,
  sideOffset = 4,
  children,
  classNames,
  styles,
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Content> & {
  classNames?: {
    arrow?: string;
  };
  styles?: {
    arrow?: React.CSSProperties;
  };
}) {
  return (
    <TooltipPrimitive.Portal>
      <TooltipPrimitive.Content
        data-slot="tooltip-content"
        sideOffset={sideOffset}
        className={cn(
          "bg-primary text-primary-foreground animate-in fade-in-0 zoom-in-95 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 z-50 w-fit origin-(--radix-tooltip-content-transform-origin) rounded-md px-3 py-1.5 text-xs text-balance",
          "bg-foreground text-background",
          className,
        )}
        {...props}
      >
        {children}
        <TooltipPrimitive.Arrow
          data-slot="tooltip-arrow"
          className={cn(
            "bg-primary fill-primary z-50 size-2.5 translate-y-[calc(-50%-2px)] rotate-45 rounded-[2px]",
            "fill-foreground bg-foreground",
            classNames?.arrow,
          )}
          style={styles?.arrow}
        />
      </TooltipPrimitive.Content>
    </TooltipPrimitive.Portal>
  );
}

export {
  TooltipProvider,
  Tooltip as TooltipRoot,
  TooltipTrigger,
} from "../../shadcn/tooltip";

export { TooltipContent };

"use client"

import * as React from "react"
import { Tooltip as TooltipPrimitive } from "radix-ui"

import { cn } from "@acme/ui/lib/utils"

function TooltipProvider({
  delayDuration = 0,
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Provider>) {
  return (
    <TooltipPrimitive.Provider
      data-slot="tooltip-provider"
      delayDuration={delayDuration}
      {...props}
    />
  )
}

function Tooltip({
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Root>) {
  return <TooltipPrimitive.Root data-slot="tooltip" {...props} />
}

function TooltipTrigger({
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Trigger>) {
  return <TooltipPrimitive.Trigger data-slot="tooltip-trigger" {...props} />
}

function TooltipContent({
  className,
  sideOffset = 0,
  children,
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Content>) {
  return (
    <TooltipPrimitive.Portal>
      <TooltipPrimitive.Content
        data-slot="tooltip-content"
        sideOffset={sideOffset}
        className={cn(
          "z-50 w-fit origin-(--radix-tooltip-content-transform-origin) animate-in rounded-md bg-foreground px-3 py-1.5 text-xs text-balance text-background fade-in-0 zoom-in-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95",
          className
        )}
        {...props}
      >
        {children}
        <TooltipPrimitive.Arrow className="z-50 size-2.5 translate-y-[calc(-50%_-_2px)] rotate-45 rounded-[2px] bg-foreground fill-foreground" />
      </TooltipPrimitive.Content>
    </TooltipPrimitive.Portal>
  )
}

export { Tooltip, TooltipTrigger, TooltipContent, TooltipProvider }
